const raw = $input.first().json.text;
const cleaned = raw.replace(/```json|```/g, '').trim();
const memo = JSON.parse(cleaned);

const company = memo.company_name || 'unknown';
const account_id = company
  .toLowerCase()
  .replace(/[^a-z0-9]/g, '_')
  .replace(/_+/g, '_')
  .replace(/^_|_$/g, '');

memo.account_id = account_id;
memo.version = 'v1';
memo.created_at = new Date().toISOString();

// Post-extraction validation: flag any missing critical fields
const criticalFields = [
  'company_name',
  'business_hours',
  'emergency_definition',
  'emergency_routing_rules',
  'non_emergency_routing_rules'
];

const validation_warnings = criticalFields
  .filter(f => !memo[f])
  .map(f => `Missing critical field: ${f}`);

if (memo.business_hours) {
  ['days', 'start', 'end'].forEach(f => {
    if (!memo.business_hours[f]) {
      validation_warnings.push(`Missing business_hours.${f}`);
    }
  });
}

return [{
  json: {
    memo,
    memo_text: JSON.stringify(memo, null, 2),
    account_id,
    validation_warnings,
    has_warnings: validation_warnings.length > 0
  }
}];

// Post-extraction validation log — always written, passed=true means no missing fields
const { account_id, validation_warnings, has_warnings } = $('Parse Memo').first().json;

const log = {
  account_id,
  version: 'v1',
  validated_at: new Date().toISOString(),
  passed: !has_warnings,
  warnings: validation_warnings
};

return [{ json: { validation_log_text: JSON.stringify(log, null, 2) } }];

const raw = $input.first().json.text;
const cleaned = raw.replace(/```json|```/g, '').trim();
const agent_spec = JSON.parse(cleaned);

const account_id = $('Parse Memo').first().json.account_id;

agent_spec.account_id = account_id;
agent_spec.version = 'v1';
agent_spec.generated_at = new Date().toISOString();

return [{ json: { agent_spec_text: JSON.stringify(agent_spec, null, 2), account_id } }];

const { account_id, memo } = $('Parse Memo').first().json;

const title = `Review v1 Agent: ${memo.company_name || account_id}`;
const description = `v1 account_memo and agent_spec generated for ${memo.company_name || account_id}. Review outputs before deploying to Retell.

Outputs:
- account_memo: /outputs/accounts/${account_id}/v1/account_memo.json
- agent_spec: /outputs/accounts/${account_id}/v1/agent_spec.json
- validation_flags: /outputs/accounts/${account_id}/v1/validation_flags.json`;

const task = {
  task_id: `${account_id}_v1_${Date.now()}`,
  title,
  account_id,
  version: 'v1',
  status: 'pending_review',
  created_at: new Date().toISOString(),
  description,
  outputs: {
    account_memo: `/outputs/accounts/${account_id}/v1/account_memo.json`,
    agent_spec: `/outputs/accounts/${account_id}/v1/agent_spec.json`,
    validation_flags: `/outputs/accounts/${account_id}/v1/validation_flags.json`
  }
};

return [{ json: { task_text: JSON.stringify(task, null, 2), asana_title: title, asana_description: description } }];
